function toggleFaq(e){const t=e.nextElementSibling;e.classList.contains("open")?(e.classList.remove("open"),t.classList.remove("open")):(e.classList.add("open"),t.classList.add("open"))}const navLinks=Array.from(document.querySelectorAll(".sn")),ids=navLinks.map(e=>e.getAttribute("href")?e.getAttribute("href").replace("#",""):null).filter(Boolean);let ticking=!1;window.addEventListener("scroll",()=>{ticking||(ticking=!0,requestAnimationFrame(()=>{let e=ids[0];ids.forEach(t=>{const n=document.getElementById(t);n&&window.scrollY>=n.offsetTop-130&&(e=t)}),navLinks.forEach(t=>{const n=t.getAttribute("href")==="#"+e;t.classList.toggle("active",n)}),ticking=!1}))},{passive:!0});